import Character from"./character.js";import MapObjects from"./objects.js";class App{mouseRippleEffect(position){this.Character=new Character;const ripple=document.createElement("div");ripple.classList.add("ripple"),ripple.style.left=`${position.clientX}px`,ripple.style.top=`${position.clientY}px`,document.getElementById("root").appendChild(ripple),this.Character.ValidateCharCount(position),setTimeout(()=>{ripple.remove(),this.Character.CharacterModel(position)},1e3)}handleMouseClick(position){this.mouseRippleEffect(position);const clientX=position.clientX,clientY=position.clientY,pageX=position.pageX,pageY=position.pageY,offsetX=position.offsetX,offsetY=position.offsetY}}new App,window.addEventListener("contextmenu",(function(event){event.preventDefault(),(new App).handleMouseClick(event)}));